--
-- Name: generate_note_search_vector(); Type: FUNCTION; Schema: public; Owner: backend_winter_waterfall_5807
--

CREATE FUNCTION public.generate_note_search_vector() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.search_vector := setweight(to_tsvector('simple', NEW.content), 'B');
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.generate_note_search_vector() OWNER TO backend_winter_waterfall_5807;

--
-- Name: notes_excerpt_update(); Type: FUNCTION; Schema: public; Owner: backend_winter_waterfall_5807
--

CREATE FUNCTION public.notes_excerpt_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  NEW.excerpt := substring(
    regexp_replace(NEW.content, '[#*`\[\]_>]', '', 'g')
    FROM 1 FOR 200
  );
  RETURN NEW;
END $$;


ALTER FUNCTION public.notes_excerpt_update() OWNER TO backend_winter_waterfall_5807;

